spec.expr:
max without (status, url, priority, id) (
  avalon_pool_rejected_percent{ip="$miner", pool_index="$pool"}
)

max without (status, url, priority, id) (
  avalon_pool_stale_percent{ip="$miner", pool_index="$pool"}
)

rate(
  max without (status, url, priority, id) (
    avalon_pool_shares_accepted_total{ip="$miner", pool_index="$pool"}
  )[5m]
)

rate(
  max without (status, url, priority, id) (
    avalon_pool_shares_rejected_total{ip="$miner", pool_index="$pool"}
  )[5m]
)

rate(
  max without (status, url, priority, id) (
    avalon_pool_stale_total{ip="$miner", pool_index="$pool"}
  )[5m]
)

max without (job, instance, url, status, priority, id) (
  avalon_pool_current_block_height{ip="$miner", pool_index="0"}
)

max without (status, url, priority, id) (
  rate(avalon_pool_bytes_sent_total{ip="$miner", pool_index="$pool"}[5m])
)

- max without (status, url, priority, id) (
    rate(avalon_pool_bytes_recv_total{ip="$miner", pool_index="$pool"}[5m])
  )
